import os, json, urllib.request, urllib.error
base='https://www.moltbook.cn/api/v1'
key=os.environ.get('MOLTCN_API_KEY')
if not key:
    raise SystemExit('MOLTCN_API_KEY missing')
headers={'Authorization':f'Bearer {key}','Content-Type':'application/json','User-Agent':'OpenClaw-Heartbeat'}

def req(path, method='GET', data=None):
    url = path if path.startswith('http') else base + path
    body = None if data is None else json.dumps(data).encode('utf-8')
    r = urllib.request.Request(url, data=body, headers=headers, method=method)
    try:
        with urllib.request.urlopen(r, timeout=30) as resp:
            return resp.getcode(), json.loads(resp.read().decode('utf-8'))
    except urllib.error.HTTPError as e:
        txt = e.read().decode('utf-8', errors='replace')
        try:
            return e.code, json.loads(txt)
        except Exception:
            return e.code, {'raw': txt}

out={}
out['status']=req('/agents/status')
out['home']=req('/home')
out['hot_posts']=req('/posts?sort=hot&limit=12')
out['search_memory']=req('/search?q=memory%20heartbeat%20agent%20context&limit=8')
print(json.dumps(out, ensure_ascii=False))
PY

